  'гҢі': 'гғ•гӮЈгғјгғҲ',
  'гҢҙ': 'гғ–гғғгӮ·гӮ§гғ«',
  'гҢө': 'гғ•гғ©гғі',
  'гҢ¶': 'гғҳгӮҜгӮҝгғјгғ«',
  'гҢ·': 'гғҡгӮҪ',
  'гҢё': 'гғҡгғӢгғ’',
  'гҢ№': 'гғҳгғ«гғ„',
  'гҢә': 'гғҡгғігӮ№',
  'гҢ»': 'гғҡгғјгӮё',
  'гҢј': 'гғҷгғјгӮҝ',
  'гҢҪ': 'гғқгӮӨгғігғҲ',
  'гҢҫ': 'гғңгғ«гғҲ',
  'гҢҝ': 'гғӣгғі',
  'гҚҖ': 'гғқгғігғү',
  'гҚҒ': 'гғӣгғјгғ«',
  'гҚӮ': 'гғӣгғјгғі',
  'гҚғ': 'гғһгӮӨгӮҜгғӯ',
  'гҚ„': 'гғһгӮӨгғ«',
  'гҚ…': 'гғһгғғгғҸ',
  'гҚҶ': 'гғһгғ«гӮҜ',
  'гҚҮ': 'гғһгғігӮ·гғ§гғі',
  'гҚҲ': 'гғҹгӮҜгғӯгғі',
  'гҚү': 'гғҹгғӘ',
  'гҚҠ': 'гғҹгғӘгғҗгғјгғ«',
  'гҚӢ': 'гғЎгӮ¬',
  'гҚҢ': 'гғЎгӮ¬гғҲгғі',
  'гҚҚ': 'гғЎгғјгғҲгғ«',
  'гҚҺ': 'гғӨгғјгғү',
  'гҚҸ': 'гғӨгғјгғ«',
  'гҚҗ': 'гғҰгӮўгғі',
